import sys

class Solution:
    def __init__(self):
        self.stack = []

    def push(self, x: int) -> None:
        self.stack.append(x)

    def pop(self) -> int:
        if self.stack:
            return self.stack.pop()
        return None

    def top(self) -> int:
        if self.stack:
            return self.stack[-1]
        return None

    def empty(self) -> bool:
        return len(self.stack) == 0

if __name__ == '__main__':
    sol = Solution()
    n = int(sys.stdin.readline().strip())
    for _ in range(n):
        op = sys.stdin.readline().strip().split()
        if op[0] == 'push':
            sol.push(int(op[1]))
        elif op[0] == 'pop':
            sol.pop()
        elif op[0] == 'top':
            print(sol.top())
        elif op[0] == 'empty':
            print('true' if sol.empty() else 'false')

