#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    vector<int> stack;
public:
    void push(int x) {
        stack.push_back(x);
    }
    int pop() {
        if (!stack.empty()) {
            int top = stack.back();
            stack.pop_back();
            return top;
        }
        return -1;
    }
    int top() {
        if (!stack.empty()) {
            return stack.back();
        }
        return -1;
    }
    bool empty() {
        return stack.empty();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    Solution sol;
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;
        if (op == "push") {
            int x;
            cin >> x;
            sol.push(x);
        } else if (op == "pop") {
            sol.pop();
        } else if (op == "top") {
            cout << sol.top() << '\n';
        } else if (op == "empty") {
            cout << (sol.empty() ? "true" : "false") << '\n';
        }
    }
    return 0;
}
